// src/echo.js
import Echo from 'laravel-echo';
import Pusher from 'pusher-js';

window.Pusher = Pusher;

let echo = null;

const enabled = String(import.meta.env.VITE_PUSHER_ENABLED || import.meta.env.VITE_REVERB_ENABLED || '').toLowerCase() === 'true';
const appKey = import.meta.env.VITE_ABLY_PUBLIC_KEY || import.meta.env.VITE_PUSHER_APP_KEY;
const token = typeof window !== 'undefined' ? (window.localStorage.getItem('token') || window.sessionStorage.getItem('token')) : null;

// Initialize Echo only when a valid token exists and key is not a placeholder
if (enabled && appKey && token && appKey !== 'your-pusher-app-key' && !appKey.includes('placeholder')) {
    // Determine the auth endpoint base (using /api prefix as registered in api.php)
    const baseUrl = (import.meta.env.VITE_API_BASE || import.meta.env.VITE_API_URL || 'https://api.besouholacrm.net').replace(/\/api\/?$/, '');
    const authEndpoint = `${baseUrl}/api/broadcasting/auth`;

    // Determine Tenant ID from subdomain
    const host = window.location.hostname; 
    const parts = host.split('.');
    const subdomain = (parts.length > 2 && parts[0] !== 'www') ? parts[0] : null;

    // Detect if using Ably or native Pusher
    const isAbly = appKey.includes(':'); 

    echo = new Echo({
        broadcaster: 'pusher',
        key: appKey,
        ...(isAbly ? {
            wsHost: 'realtime-pusher.ably.io',
            wsPort: 443,
            disableStats: true,
            encrypted: true,
        } : {
            cluster: import.meta.env.VITE_PUSHER_APP_CLUSTER || 'mt1',
        }),
        forceTLS: true,
        authEndpoint: authEndpoint,
        auth: {
            headers: {
                Authorization: `Bearer ${token}`,
                Accept: 'application/json',
                ...(subdomain ? { 'X-Tenant-Id': subdomain } : {}),
            },
        },
    });
}

export default echo;
